// nodes/textNode.js
import { BaseNode } from './BaseNode';
import { FileText } from 'lucide-react';
import { Handle, Position } from 'reactflow';
import { useMemo } from 'react';

const extractVars = (text) => {
  const regex = /\{\{\s*([a-zA-Z_$][a-zA-Z0-9_$]*)\s*\}\}/g;
  const vars = [];
  let match;
  while ((match = regex.exec(text)) !== null) {
    if (!vars.includes(match[1])) vars.push(match[1]);
  }
  return vars;
};

export const TextNode = ({ id, data, selected }) => {
  const text = data?.text || '{{input}}';
  const vars = useMemo(() => extractVars(text), [text]);

  const accentColor = 'var(--accent-amber)';

  return (
    <BaseNode
      id={id}
      title="Text"
      icon={FileText}
      accentColor={accentColor}
      outputs={[{ id: 'output', label: 'output' }]}
      selected={selected}
    >
      {/* Dynamic variable handles (rendered outside BaseNode handles) */}
      {vars.map((v, i) => {
        const top = vars.length === 1
          ? 50
          : 20 + (i / (vars.length - 1)) * 60;
        return (
          <div key={v} style={{ position: 'absolute', left: 0, top: `${top}%`, transform: 'translateY(-50%)' }}>
            <Handle
              type="target"
              position={Position.Left}
              id={`var-${v}`}
              style={{
                left: -7,
                width: 14,
                height: 14,
                background: 'var(--bg-surface)',
                border: `2px solid ${accentColor}`,
                borderRadius: '50%',
                transition: 'all 0.2s',
              }}
            />
            <span
              style={{
                position: 'absolute',
                left: -16,
                top: '50%',
                transform: 'translate(-100%, -50%)',
                fontSize: '11px',
                color: 'var(--text-tertiary)',
                whiteSpace: 'nowrap',
                pointerEvents: 'none',
              }}
            >
              {v}
            </span>
          </div>
        );
      })}

      <div style={{ fontSize: '12px', color: 'var(--text-secondary)', background: 'var(--bg-app)', padding: '8px', borderRadius: '6px', border: '1px solid var(--border-subtle)', maxHeight: '60px', overflow: 'hidden', textOverflow: 'ellipsis', display: '-webkit-box', WebkitLineClamp: 3, WebkitBoxOrient: 'vertical', fontFamily: 'monospace' }}>
        {text}
      </div>
      {vars.length > 0 && (
        <div style={{ fontSize: '11px', color: 'var(--text-tertiary)', marginTop: '8px', display: 'flex', gap: '4px', flexWrap: 'wrap' }}>
          {vars.map((v) => (
            <span key={v} style={{ background: 'rgba(245,158,11,0.1)', color: 'var(--accent-amber)', borderRadius: '4px', padding: '2px 6px' }}>{v}</span>
          ))}
        </div>
      )}
    </BaseNode>
  );
};
